{
  "decision_summary": "The chip temperature (89.26°C) exceeds the limit (85.0°C). Since geometry changes are hitting legality limits and recent improvements have stalled, the strategy shifts to material tuning. Increasing the heat spreader conductivity is the highest-priority lever to enhance lateral heat spreading and reduce the peak temperature.",
  "changes": [
    {
      "path": "materials.spreader_material.conductivity",
      "action": "set",
      "old": 500.0,
      "new": 1000.0,
      "reason": "Doubling the spreader conductivity (within the allowed 2.0x ratio) will significantly improve lateral heat distribution, lowering the local hot spot on the chip."
    }
  ],
  "expected_effects": [
    "Reduction in chip_max_temperature below 85.0°C",
    "More uniform temperature profile across the heat spreader"
  ],
  "risk_notes": [
    "Diminishing returns may occur if the bottleneck shifts to the base plate or boundary conditions rather than the spreader itself.",
    "High conductivity values assume idealized material behavior; ensure physical plausibility in downstream validation."
  ]
}
